messages.content:
Para usar Terraform com OCI:

**1. Provider configuration:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region               = "us-phoenix-1"
  tenancy_ocid         = var.tenancy_ocid
  user_ocid            = var.user_ocid
  fingerprint          = var.fingerprint
  private_key_path     = var.private_key_path
}
```

**2. Variables (variables.tf):**
```hcl
variable "tenancy_ocid" {}
variable "user_ocid" {}
variable "fingerprint" {}
variable "private_key_path" {}
variable "compartment_ocid" {
  description = "Compartment OCID"
  type        = string
}
```

**3. Resources:**
```hcl
resource "oci_core_vcn" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "vcn-sandbox"
  cidr_block     = "10.0.0.0/16"
  dns_label      = "vcn715"
}

resource "oci_core_subnet" "public" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.main.id
  cidr_block     = "10.0.1.0/24"
  display_name   = "public-subnet"
  dns_label      = "pub715"
}
```

**4. Execução:**
```bash
terraform init
terraform plan -var-file="terraform.tfvars"
terraform apply -var-file="terraform.tfvars"
```

**5. Remote state no OCI Object Storage:**
```hcl
terraform {
  backend "s3" {
    bucket   = "terraform-state"
    key      = "sandbox/terraform.tfstate"
    region   = "us-phoenix-1"
    endpoint = "https://us-phoenix-1.objectstorage.oci.oraclecloud.com"
  }
}
```

**Boas práticas:**
- Use modules para reutilização
- Pin provider versions
- Nunca commite state files
- Use workspaces para multi-environment

